chart.options:
chart: {
  width: 380,
  type: 'pie',
},
labels: [
  'Monday',
  'Tuesday',
  'Wednesday',
  'Thursday',
  'Friday',
  'Saturday',
],
theme: {
  monochrome: {
    enabled: true,
  },
},
plotOptions: {
  pie: {
    dataLabels: {
      offset: -5,
    },
  },
},
grid: {
  padding: {
    top: 0,
    bottom: 0,
    left: 0,
    right: 0,
  },
},
dataLabels: {
  formatter(val, opts) {
    const name = opts.w.globals.labels[opts.seriesIndex]
    return [name, val.toFixed(1) + '%']
  },
},
legend: {
  show: false,
},
